  1	/**
  2	 * A modal component displaying connection statuses (successful, failed, unreachable) for a source.
  3	 * Utilizes expandable lists and status icons for clarity.
  4	 *
  5	 * @module connectionsModal
  6	 */
  7	import React, { useCallback, useState } from 'react';
  8	import { Modal, ModalVariant, Button, Icon, List, ListItem } from '@patternfly/react-core';
  9	import { ExclamationCircleIcon, ExclamationTriangleIcon, CheckCircleIcon } from '@patternfly/react-icons';
 10	import { Tbody, Tr, Td, Table, ExpandableRowContent } from '@patternfly/react-table';
 11	import { type SourceType, type Connections } from '../../types/types';
 12	import './showSourceConnectionsModal.css';
 13	
 14	interface ShowConnectionsModalProps {
 15	  isOpen: boolean;
 16	  source?: Pick<SourceType, 'name'>;
 17	  onClose?: () => void;
 18	  connections: Connections;
 19	}
 20	
 21	const ShowConnectionsModal: React.FC<ShowConnectionsModalProps> = ({
 22	  isOpen,
 23	  source,
 24	  onClose = Function.prototype,
 25	  connections
 26	}) => {
 27	  const [expanded, setExpanded] = useState<string[]>([]);
 28	  const onToggle = useCallback(
 29	    section => {
 30	      const index = expanded.indexOf(section);
 31	      const newExpanded =
 32	        index >= 0
 33	          ? [...expanded.slice(0, index), ...expanded.slice(index + 1, expanded.length)]
 34	          : [...expanded, section];
 35	      setExpanded(newExpanded);
 36	    },
 37	    [expanded]
 38	  );
 39	
 40	  return (
 41	    <Modal
 42	      variant={ModalVariant.small}
 43	      title={source?.name}
 44	      isOpen={isOpen}
 45	      onClose={() => {
 46	        setExpanded([]);
 47	        return onClose();
 48	      }}
 49	      actions={[
 50	        <Button
 51	          key="cancel"
 52	          variant="secondary"
 53	          onClick={() => {
 54	            setExpanded([]);
 55	            return onClose();
 56	          }}
 57	        >
 58	          Close
 59	        </Button>
 60	      ]}
 61	    >
 62	      <Table aria-label={'Connections lists'}>
 63	        {[
 64	          {
 65	            category: 'failed',
 66	            icon: (
 67	              <Icon status="danger">
 68	                <ExclamationCircleIcon />
 69	              </Icon>
 70	            ),
 71	            label: 'Failed connections'
 72	          },
 73	          {
 74	            category: 'unreachable',
 75	            icon: (
 76	              <Icon status="warning">
 77	                <ExclamationTriangleIcon />
 78	              </Icon>
 79	            ),
 80	            label: 'Unreachable systems'
 81	          },
 82	          {
 83	            category: 'successful',
 84	            icon: (
 85	              <Icon status="success">
 86	                <CheckCircleIcon />
 87	              </Icon>
 88	            ),
 89	            label: 'Successful connections'
 90	          }
 91	        ].map((obj, rowIndex) => {
 92	          return (
 93	            <Tbody key={obj.category} isExpanded={expanded.includes(obj.category)}>
 94	              <Tr>
 95	                <Td
 96	                  width={10}
 97	                  expand={{
 98	                    rowIndex,
 99	                    isExpanded: expanded.includes(obj.category),
100	                    onToggle: () => onToggle(obj.category),
101	                    expandId: `${obj.category}-expandable`
102	                  }}
103	                />
104	                <Td width={10}>{obj.icon}</Td>
105	                <Td width={80}>{obj.label}</Td>
106	              </Tr>
107	              <Tr isExpanded={expanded.includes(obj.category)}>
108	                <Td />
109	                <Td />
110	                <Td>
111	                  <ExpandableRowContent>
112	                    <List isPlain>
113	                      {(connections[obj.category]?.length &&
114	                        connections[obj.category].map(connection => (
115	                          <ListItem key={connection.name}>{connection.name}</ListItem>
116	                        ))) || <ListItem>N/A</ListItem>}
117	                    </List>
118	                  </ExpandableRowContent>
119	                </Td>
120	              </Tr>
121	            </Tbody>
122	          );
123	        })}
124	      </Table>
125	    </Modal>
126	  );
127	};
128	
129	export { ShowConnectionsModal as default, ShowConnectionsModal, type ShowConnectionsModalProps };

